import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [role, setRole] = useState(null);
  const [students, setStudents] = useState([]);
  const [view, setView] = useState("exam"); // exam ama xadiris
  const [qaybta, setQaybta] = useState("Dhamaan");
  const [currentUser, setCurrentUser] = useState(null);

  useEffect(() => {
    if (role === 'admin') axios.get('http://localhost:3000/admin/students').then(res => setStudents(res.data));
  }, [role]);

  // Xisaabinta Xadiriska (Percentage)
  const getAttendanceStats = (x) => {
    const total = x.joogay + x.maqnaa;
    const percent = total === 0 ? 0 : Math.round((x.joogay / total) * 100);
    return { total, percent };
  };

  const filtered = students.filter(s => {
    const fNum = parseInt(s.id.substring(1, 3));
    if (qaybta === "1/4") return fNum <= 4;
    if (qaybta === "5/8") return fNum >= 5 && fNum <= 8;
    if (qaybta === "9/12") return fNum >= 9;
    return true;
  });

  const AdminView = () => (
    <div style={{ padding: '20px' }}>
      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
        <button onClick={() => setView("exam")} style={view === "exam" ? activeBtn : btnStyle}>Imtixaanka</button>
        <button onClick={() => setView("xadiris")} style={view === "xadiris" ? activeBtn : btnStyle}>Xadiriska Ardayda</button>
      </div>

      <select onChange={e => setQaybta(e.target.value)} style={{padding: '10px', marginBottom: '20px'}}>
        <option value="Dhamaan">Dhamaan 1-12</option>
        <option value="1/4">1/4 (Primary)</option>
        <option value="5/8">5/8 (Intermediate)</option>
        <option value="9/12">9/12 (Secondary)</option>
      </select>

      <table border="1" width="100%" style={{ borderCollapse: 'collapse', textAlign: 'center', background: 'white' }}>
        <thead style={{background: '#2c3e50', color: 'white'}}>
          {view === "exam" ? (
            <tr><th>ID</th><th>Magaca</th><th>Fasalka</th><th>Xisaab</th><th>Total</th></tr>
          ) : (
            <tr><th>ID</th><th>Magaca Ardayga</th><th>Fasalka</th><th>Xadiris (Action)</th><th>Boqolley (%)</th></tr>
          )}
        </thead>
        <tbody>
          {filtered.map(s => (
            <tr key={s.id}>
              <td>{s.id}</td><td>{s.magaca}</td><td>{s.fasalka}</td>
              {view === "exam" ? (
                <>
                  <td><input type="number" onBlur={e => axios.put(`http://localhost:3000/admin/update/${s.id}`, {type: 'exam', data: {Xisaab: e.target.value}})} defaultValue={s.exam.Xisaab} /></td>
                  <td>{Object.values(s.exam).reduce((a,b) => Number(a)+Number(b), 0)}</td>
                </>
              ) : (
                <>
                  <td>
                    <button onClick={() => axios.put(`http://localhost:3000/admin/update/${s.id}`, {type: 'xadiris', status: 'sax'}).then(() => alert(s.magaca + " waa la xadiiriyey!"))} style={{background: 'green', color: 'white'}}>√ Sax</button>
                    <button onClick={() => axios.put(`http://localhost:3000/admin/update/${s.id}`, {type: 'xadiris', status: 'maqan'})} style={{background: 'red', color: 'white'}}>X Maqan</button>
                  </td>
                  <td style={{fontWeight: 'bold', color: getAttendanceStats(s.xadiris).percent > 70 ? 'green' : 'red'}}>
                    {getAttendanceStats(s.xadiris).percent}%
                  </td>
                </>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  return (
    <div style={{ fontFamily: 'Arial', background: '#f0f2f5', minHeight: '100vh' }}>
      {!role ? (
        <div style={{textAlign: 'center', paddingTop: '100px'}}>
          <h1>Dugsi Management System</h1>
          <button onClick={() => {
            const p = prompt("Geli Admin Password (admin1234):");
            axios.post('http://localhost:3000/login', {type: 'admin', password: p}).then(() => setRole('admin')).catch(() => alert("Password-ka waa khalad!"));
          }} style={loginBtn}>Geli Maamule</button>
        </div>
      ) : <AdminView />}
    </div>
  );
}

const btnStyle = { padding: '10px 20px', cursor: 'pointer', border: 'none', borderRadius: '5px', background: '#ddd' };
const activeBtn = { ...btnStyle, background: '#1a73e8', color: 'white' };
const loginBtn = { padding: '20px 40px', fontSize: '18px', cursor: 'pointer', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '10px' };

export default App;
